#include <stdio.h>

int main(void) {
    long long n;
    long long sum = 0;

    if (scanf("%lld", &n) != 1) {
        return 0;
    }

    if (n == 0) {
        printf("0\n");
        return 0;
    }

    while (n > 0) {
        int digit = (int)(n % 10);
        if (digit % 2 == 0) {
            sum += digit;
        }
        n /= 10;
    }

    printf("%lld\n", sum);
    return 0;
}

#include <stdio.h>

int main(void) {
    long long n;
    int sum = 0;

    if (scanf("%lld", &n) != 1) {
        return 0;
    }

    if (n == 0) {
        printf("LUCKY\n");
        return 0;
    }

    while (n > 0) {
        sum += (int)(n % 10);
        n /= 10;
    }

    if (sum % 3 == 0) {
        printf("LUCKY\n");
    } else {
        printf("NOT LUCKY\n");
    }

    return 0;
}

#include <stdio.h>

int main(void) {
    int t;

    if (scanf("%d", &t) != 1) {
        return 0;
    }

    if (t < 0) {
        printf("FREEZE\n");
    } else if (t <= 15) {
        printf("COLD\n");
    } else if (t <= 28) {
        printf("WARM\n");
    } else {
        printf("HOT\n");
    }

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    int count = 0;
    int i;

    if (scanf("%d", &n) != 1) {
        return 0;
    }

    for (i = 0; i < n; i++) {
        int x;
        if (scanf("%d", &x) != 1) {
            return 0;
        }
        if (x < 0) {
            x = -x;
        }
        if (x % 10 == 7) {
            count++;
        }
    }

    printf("%d\n", count);
    return 0;
}

#include <stdio.h>

int main(void) {
    int x;
    int sum = 0;

    while (scanf("%d", &x) == 1) {
        if (x == 0) {
            break;
        }
        sum += x;
    }

    printf("%d\n", sum);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n, k;
    int sum = 0;
    int i;

    if (scanf("%d %d", &n, &k) != 2) {
        return 0;
    }

    for (i = 1; i <= n; i++) {
        if (i % k != 0) {
            sum += i;
        }
    }

    printf("%d\n", sum);
    return 0;
}

