#include <stdio.h>

int main(void) {
    int n;
    int i;
    long long total = 0;

    if (scanf("%d", &n) != 1) {
        return 0;
    }

    for (i = 1; i <= n; i++) {
        int steps;
        if (scanf("%d", &steps) != 1) {
            return 0;
        }
        total += steps;
        if (i % 2 == 1) {
            total += 100;
        }
    }

    printf("%lld\n", total);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    int score = 0;
    int i;

    if (scanf("%d", &n) != 1) {
        return 0;
    }

    for (i = 0; i < n; i++) {
        int x;
        if (scanf("%d", &x) != 1) {
            return 0;
        }
        if (x % 2 == 0) {
            score += 2;
        } else if (x % 3 == 0) {
            score -= 1;
        }
    }

    printf("%d\n", score);
    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    int i;
    int found = 0;
    int answer = 0;

    if (scanf("%d", &n) != 1) {
        return 0;
    }

    for (i = 0; i < n; i++) {
        int x;
        if (scanf("%d", &x) != 1) {
            return 0;
        }
        if (!found && x >= 0) {
            found = 1;
            answer = x;
        }
    }

    if (found) {
        printf("%d\n", answer);
    } else {
        printf("NONE\n");
    }

    return 0;
}
